import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jfree.data.time.TimePeriodValues;
import org.jfree.data.time.SimpleTimePeriod;
import static org.junit.Assert.assertEquals;

import java.util.Date;

public class StepDefs {
    private TimePeriodValues series;
    private SimpleTimePeriod period;
    private Number value;

    @Given("^a \"TimePeriodValues\" series named \"(.*)\"$")
    public void createSeries(String name) throws Throwable {
        series = new TimePeriodValues(name);
    }

    @Given("^I add a period from (\\d+) to (\\d+) with value ([-+]?[0-9]*\\.?[0-9]+)$")
    public void addPeriod(long start, long end, double val) throws Throwable {
        Date startDate = new Date(start);
        Date endDate = new Date(end);
        period = new SimpleTimePeriod(startDate, endDate);
        value = val;
        series.add(period, value);
    }

    @When("^I add a period from (\\d+) to (\\d+) with value ([-+]?[0-9]*\\.?[0-9]+)$")
    public void whenAddPeriod(long start, long end, double val) throws Throwable {
        Date startDate = new Date(start);
        Date endDate = new Date(end);
        period = new SimpleTimePeriod(startDate, endDate);
        value = val;
        series.add(period, value);
    }

    @Then("^the index of the maximum middle value should be (\\d+)$")
    public void verifyMaxMiddleIndex(int expectedIndex) throws Throwable {
        int actualIndex = -1;
        try {
            // Access the protected getMaxMiddleIndex method via reflection
            java.lang.reflect.Method method = series.getClass().getDeclaredMethod("getMaxMiddleIndex");
            method.setAccessible(true);
            actualIndex = (Integer) method.invoke(series);
        } catch (Exception e) {
            throw new RuntimeException("Failed to access getMaxMiddleIndex method", e);
        }

        assertEquals("Maximum middle index mismatch", expectedIndex, actualIndex);
    }
}

